// explain
const log = global.get("logger");
log(this,"Using `Self-consumption` to charge with surplus PV")

// use the self consumption strategy to charge when there is PV surplus
msg.target = "Self-consumption";

// tell that strategy to disallow discharging
const DISCHARGE_DISABLED = true;
RED.util.setMessageProperty(msg,"advanced_settings.discharge_disabled",DISCHARGE_DISABLED,true);

return msg;

// Log unhandled exception
const handle = global.get('unhandledException');
if(handle) handle(this);

// Check origin of msg execution
if (msg._linkSource) {
    return msg; // Origin: some other flow
} else {
    return null; // Origin: this flow. Stop to prevent 'Missing return' warning
}

/* Mode selection 
 * 
 * Peak shaving can be triggered by:
 * - Grid power exceeds the import/export limit set by the user
 * 
 * Peak shaving will persist while:
 * - Grid power exceeds the import/export limit set by the user
 * - Batteries are applied to keep system below the limit set by the user
 * 
 * The first is checked in this node.
 * The latter is checked in the last function node of the Peak Shaving flow.
 * Both set the `last_power_limit_violation` flow variable to Date.now() to persist peak shaving.
 * 
 * PEAK_SHAVING_TIMEOUT_SEC is advised to be kept above atleast 3-5 seconds, to account for rate limiters and other power saving options.
*/

// Timestamp
const now = Date.now();

// Logger
const log = global.get("logger");

// Configuration & State recovery
const PEAK_SHAVING_TIMEOUT_SEC = 10;
let isPeakShaving = flow.get("is_peak_shaving") ?? false;
let lastPowerLimitViolation = flow.get("last_power_limit_violation") ?? now;
let isPowerLimitViolation = false;

// Input Data
const hasImportLimit = RED.util.getMessageProperty(msg, "grid_power_has_limit_import") || false;
const importLimit = parseInt(RED.util.getMessageProperty(msg, "grid_power_limit_import") || 0);
const P1_power = parseInt(RED.util.getMessageProperty(msg, "grid_power") || 0);

// ACTIVATE shaving
if (hasImportLimit && (P1_power > importLimit)) {
    isPeakShaving = true;
    isPowerLimitViolation = true;
}

// UPDATE timer or continue
if (isPowerLimitViolation) lastPowerLimitViolation = now;

// CALCULATE release logic
// Seconds since the last time the power limit was exceeded
let secondsSinceLastViolation = Math.floor((now - lastPowerLimitViolation) / 1000);

// RELEASE shaving logic
// Only release if we are currently shaving AND the timeout has passed
if (isPeakShaving && (secondsSinceLastViolation >= PEAK_SHAVING_TIMEOUT_SEC)) {
    isPeakShaving = false;
    log(this,"Peak Shaving released, resume normal operation");
}

// UI & OUTPUT Logic
if (isPeakShaving) {
    // Timeout progress
    const secondsRemaining = PEAK_SHAVING_TIMEOUT_SEC - secondsSinceLastViolation;
    // Set grid power limit
    msg.payload = importLimit;
    // UI
    node.status({
        fill: "yellow",
        shape: "dot",
        text: isPowerLimitViolation ? `Peak Shaving` :`Peak Shaving: release in ${secondsRemaining}s`
    });
} else {
    // UI
    node.status({
        fill: "green",
        shape: "dot",
        text: "Grid OK - Charging PV"
    });
}

// Persist state for next run
flow.set("is_peak_shaving", isPeakShaving); 
if (isPowerLimitViolation) flow.set("last_power_limit_violation", now); // Power limit exceeded. Update the lastPowerLimitViolation timestamp to current time

// Finalize msg
RED.util.setMessageProperty(msg, "strategy.is_peak_shaving", isPeakShaving, true);

// OUTPUT
return msg;

// Logger
const log = global.get("logger");

// Explain
log(this,`**Peak shaving mode** postponing '${msg.target}' strategy`);

// Use the PID controller strategy
msg.target = "Self-consumption";
// Set the grid power limit
msg.house_target_grid_consumption_in_w = msg.payload;
// Tell the strategy to discharging only
const CHARGE_DISABLED = true;
RED.util.setMessageProperty(msg, "advanced_settings.charge_disabled", CHARGE_DISABLED, true);

return msg;

// Logger
const log = global.get("logger");

// INPUT
const PID_assigned = msg.pid?.load_assigned ?? 0; // calculated battery power delivery, see footnote_1 why this is 0 by default
const isCharging = msg.batteries_charging || false;

// HOLD peak shave when:
if(PID_assigned > 0 && !isCharging) {
    // The batteries are still required to reduce the power peak
    log(this,`**Peak shaving continues**, batteries still required for peak reduction`);
    // Reset timeout timer
    flow.set("last_power_limit_violation", Date.now()); 
    // UI
    node.status({fill:"yellow",shape:"dot",text:`Holding peak shave, batteries still required for ${PID_assigned} W`});
} else {
    // No solution or batteries not required - let timer run out
    node.status({fill:"green",shape:"dot",text:`Relax`});
}

return msg;

// FOOTNOTE_1: 
// Self-consumption won't return `msg.solutions` nor `msg.pid.load_assigned` when:
// - P1 is near or at it's target grid consumption (aka inside deadband)
// - when a non-blocking error occurs
// 
// This code does not specifically account for these cases, but applies a TIMEOUT mechanism instead.
// As PID_assigned is kept 0, the timer won't be updated and runs out.
